CREATE TABLE "ProjectCategory" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "ProjectCategory_pkey" PRIMARY KEY("id"));
CREATE TABLE "Project" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"status" TEXT NOT NULL DEFAULT 'NOT_STARTED',"startDate" TIMESTAMP(3),"endDate" TIMESTAMP(3),"categoryId" TEXT,"customFields" JSONB NOT NULL DEFAULT '{}',"createdBy" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Project_pkey" PRIMARY KEY("id"));
CREATE TABLE "ProjectTask" ("id" TEXT NOT NULL,"projectId" TEXT NOT NULL,"subject" TEXT NOT NULL,"description" TEXT,"status" TEXT NOT NULL DEFAULT 'TODO',"priority" TEXT NOT NULL DEFAULT 'MEDIUM',"assignedTo" TEXT,"startDate" TIMESTAMP(3),"endDate" TIMESTAMP(3),"customFields" JSONB NOT NULL DEFAULT '{}',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "ProjectTask_pkey" PRIMARY KEY("id"));
CREATE TABLE "ProjectTimeLog" ("id" TEXT NOT NULL,"projectId" TEXT NOT NULL,"taskId" TEXT,"userName" TEXT NOT NULL,"minutes" INTEGER NOT NULL,"note" TEXT,"loggedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ProjectTimeLog_pkey" PRIMARY KEY("id"));
CREATE TABLE "ProjectSettings" ("id" TEXT NOT NULL DEFAULT 'default',"customField1" TEXT,"customField2" TEXT,"customField3" TEXT,"customField4" TEXT,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "ProjectSettings_pkey" PRIMARY KEY("id"));
CREATE UNIQUE INDEX "ProjectCategory_name_key" ON "ProjectCategory"("name");CREATE INDEX "Project_status_idx" ON "Project"("status");CREATE INDEX "Project_categoryId_idx" ON "Project"("categoryId");CREATE INDEX "ProjectTask_projectId_status_idx" ON "ProjectTask"("projectId","status");CREATE INDEX "ProjectTimeLog_projectId_idx" ON "ProjectTimeLog"("projectId");CREATE INDEX "ProjectTimeLog_taskId_idx" ON "ProjectTimeLog"("taskId");
ALTER TABLE "Project" ADD CONSTRAINT "Project_categoryId_fkey" FOREIGN KEY("categoryId") REFERENCES "ProjectCategory"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "ProjectTask" ADD CONSTRAINT "ProjectTask_projectId_fkey" FOREIGN KEY("projectId") REFERENCES "Project"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "ProjectTimeLog" ADD CONSTRAINT "ProjectTimeLog_projectId_fkey" FOREIGN KEY("projectId") REFERENCES "Project"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "ProjectTimeLog" ADD CONSTRAINT "ProjectTimeLog_taskId_fkey" FOREIGN KEY("taskId") REFERENCES "ProjectTask"("id") ON DELETE SET NULL ON UPDATE CASCADE;
